SourceCode.Declaration:
/// <summary>
/// Response data contract carrying the subject of the looked-up note header.
/// </summary>
[DataContractAttribute]
class ConDemoNoteLookupResponse
{
    Name subject;
}

Method.Source:
[DataMemberAttribute('Subject')]
public Name parmSubject(Name _subject = subject)
{
    subject = _subject;
    return subject;
}
